SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1000000000.0) AND (t.Risk_Rating <= 6) AND (t.D_RSI < 0.27) AND (t.PE < 7.4) AND (t.PE>1.2) AND (t.ROE_Min3Y > 0.04) AND (t.PB < 1.1*t.PB_MA5Y - 0.3*t.PB_SD5Y) AND (t.PCF > 1.0) AND (t.PCF <38.0) AND ((t.Cash_P0/ (t.LtDebt_P0+1) > 0.095) OR (ABS(t.IntCov_P0) > 2.6)) AND (t.NP_P0 > 0) ORDER BY t.ticker, t.time